mapper.select:
SELECT id, title, description, difficulty, target_goal, target_body_part, equipment_requirement, duration_minutes, impact_level, safety_notes, source_type, source_video_id, platform_channel, embed_url, posture_type, video_url, thumbnail_url, is_curated, active, created_at, updated_at FROM workout_video WHERE active = TRUE
AND target_goal = #{query.goal}
AND duration_minutes <= #{query.maxDurationMinutes}
AND impact_level != 'HIGH'
AND target_body_part != 'CORE'
AND posture_type = #{query.postureType}
AND (target_body_part = #{query.targetArea} OR target_body_part = 'FULL_BODY')
AND impact_level = #{query.impactLevel}
AND equipment_requirement IN ('NONE', 'CHAIR')
AND equipment_requirement = 'NONE'
AND (equipment_requirement = 'NONE' OR equipment_requirement = #{query.equipment})
ORDER BY CASE WHEN target_goal = #{query.goal} THEN 0 ELSE 1 END, CASE WHEN posture_type = #{query.postureType} THEN 0 ELSE 1 END, CASE WHEN target_body_part = #{query.targetArea} THEN 0 ELSE 1 END, CASE WHEN impact_level = #{query.impactLevel} THEN 0 ELSE 1 END, CASE WHEN equipment_requirement = #{query.equipment} THEN 0 ELSE 1 END, duration_minutes ASC LIMIT 6
